import React, { createContext, useContext, useEffect, useMemo, useReducer } from 'react';
import { View, ActivityIndicator, Button, Text, TextInput, StyleSheet } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_KEY = 'auth_state_v1';

const AuthContext = createContext(null);

const initialState = {
  isLoading: true,
  isAuthenticated: false,
  token: null,
  user: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: !!action.payload?.token,
        token: action.payload?.token ?? null,
        user: action.payload?.user ?? null,
      };
    case 'LOGIN':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: true,
        token: action.payload.token,
        user: action.payload.user,
      };
    case 'LOGOUT':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: false,
        token: null,
        user: null,
      };
    default:
      return state;
  }
}

async function saveAuthSession(session) {
  await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(session));
}

async function clearAuthSession() {
  await AsyncStorage.removeItem(STORAGE_KEY);
}

async function loadAuthSession() {
  const raw = await AsyncStorage.getItem(STORAGE_KEY);
  return raw ? JSON.parse(raw) : null;
}

async function fakeLoginApi({ email, password }) {
  await new Promise(resolve => setTimeout(resolve, 900));
  if (!email || !password) {
    throw new Error('Email and password are required');
  }
  return {
    token: 'demo-token-' + Date.now(),
    user: {
      id: 'u1',
      name: 'Demo User',
      email,
    },
  };
}

function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  useEffect(() => {
    let mounted = true;

    const bootstrap = async () => {
      try {
        const session = await loadAuthSession();
        if (mounted && session?.token) {
          dispatch({ type: 'RESTORE', payload: session });
        } else if (mounted) {
          dispatch({ type: 'RESTORE', payload: null });
        }
      } catch {
        if (mounted) {
          dispatch({ type: 'RESTORE', payload: null });
        }
      }
    };

    bootstrap();

    return () => {
      mounted = false;
    };
  }, []);

  const value = useMemo(
    () => ({
      ...state,
      signIn: async credentials => {
        const session = await fakeLoginApi(credentials);
        await saveAuthSession(session);
        dispatch({ type: 'LOGIN', payload: session });
      },
      signOut: async () => {
        await clearAuthSession();
        dispatch({ type: 'LOGOUT' });
      },
      updateUser: async user => {
        const session = { token: state.token, user };
        await saveAuthSession(session);
        dispatch({ type: 'LOGIN', payload: session });
      },
    }),
    [state]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}

function SplashScreen() {
  return (
    <View style={styles.center}>
      <ActivityIndicator size="large" />
      <Text style={styles.subtitle}>Loading session...</Text>
    </View>
  );
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = React.useState('demo@example.com');
  const [password, setPassword] = React.useState('password123');
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState('');

  const onLogin = async () => {
    try {
      setLoading(true);
      setError('');
      await signIn({ email, password });
    } catch (e) {
      setError(e.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Sign In</Text>
      <TextInput
        autoCapitalize="none"
        keyboardType="email-address"
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        style={styles.input}
      />
      <TextInput
        secureTextEntry
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        style={styles.input}
      />
      {!!error && <Text style={styles.error}>{error}</Text>}
      <Button title={loading ? 'Signing In...' : 'Sign In'} onPress={onLogin} disabled={loading} />
    </View>
  );
}

function HomeScreen() {
  const { user, token, signOut } = useAuth();

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome</Text>
      <Text style={styles.subtitle}>Name: {user?.name}</Text>
      <Text style={styles.subtitle}>Email: {user?.email}</Text>
      <Text style={styles.token}>Token: {token}</Text>
      <Button title="Sign Out" onPress={signOut} />
    </View>
  );
}

function AppContent() {
  const { isLoading, isAuthenticated } = useAuth();

  if (isLoading) return <SplashScreen />;
  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

